import 'package:injectable/injectable.dart'; @singleton class AnalyticsManager { void logScreenView(String screenName) {} void logEvent(String name, {Map<String, dynamic>? params}) {} void logError(String error, {Map<String, dynamic>? extra}) {} void setUserId(String uid) {} void logFeatureUsed(String feature) => logEvent('feature_used', params: {'name': feature}); void logSessionStart(String type) => logEvent('session_start', params: {'type': type}); void logSessionEnd(int seconds) => logEvent('session_end', params: {'duration': seconds.toString()}); }
